//! Native all-channel shootoff client for `gnosis-foil-control`.
//!
//! Sends the same RF Fibonacci request over HTTP/BWF2 and Flow/UDP/BWF2,
//! records both timings, and reports the fastest channel per request. The
//! default keeps `n=20` so it remains comparable with the historical fib20
//! shootout.

use distributed_inference::gnosis_foil::FoilFlowFrame;
use serde::Serialize;
use std::env;
use std::io::{Read, Write};
use std::net::{TcpStream, UdpSocket};
use std::time::{Duration, Instant};

const BWF2_SIZE: usize = 128;

#[derive(Debug)]
struct Cli {
    host: String,
    http_port: u16,
    udp_port: u16,
    path: String,
    requests: usize,
    timeout_ms: u64,
    mode: ShootoffMode,
    response_format: ResponseFormat,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum ShootoffMode {
    All,
    Http,
    Udp,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum ResponseFormat {
    Bwf2,
    Json,
    Any,
}

impl ResponseFormat {
    fn parse(value: &str) -> Result<Self, String> {
        match value {
            "bwf2" | "binary" => Ok(Self::Bwf2),
            "json" => Ok(Self::Json),
            "any" => Ok(Self::Any),
            _ => Err(format!("unknown response format: {value}")),
        }
    }
}

impl ShootoffMode {
    fn parse(value: &str) -> Result<Self, String> {
        match value {
            "all" | "fastest" => Ok(Self::All),
            "http" => Ok(Self::Http),
            "udp" | "flow" | "aeon-flow" => Ok(Self::Udp),
            _ => Err(format!("unknown mode: {value}")),
        }
    }
}

#[derive(Clone, Copy, Debug, Serialize)]
struct TimingStats {
    n: usize,
    p50_us: f64,
    p95_us: f64,
    p99_us: f64,
    mean_us: f64,
    variance_us2: f64,
    min_us: f64,
    max_us: f64,
}

#[derive(Debug, Serialize)]
struct ShootoffReport {
    engine: String,
    requests: usize,
    http: TimingStats,
    udp: TimingStats,
    fastest: TimingStats,
    http_wins: usize,
    udp_wins: usize,
}

fn parse_cli() -> Result<Cli, String> {
    let mut cli = Cli {
        host: "127.0.0.1".to_string(),
        http_port: 8886,
        udp_port: 9086,
        path: "/.aeon/rf-fibonacci?n=20&repetitions=1".to_string(),
        requests: 500,
        timeout_ms: 1_000,
        mode: ShootoffMode::All,
        response_format: ResponseFormat::Bwf2,
    };
    let mut args = env::args().skip(1);
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--host" => cli.host = args.next().ok_or("--host requires a value")?,
            "--http-port" => {
                cli.http_port = args
                    .next()
                    .ok_or("--http-port requires a value")?
                    .parse()
                    .map_err(|_| "--http-port must be a u16".to_string())?;
            }
            "--udp-port" | "--flow-port" => {
                cli.udp_port = args
                    .next()
                    .ok_or("--udp-port requires a value")?
                    .parse()
                    .map_err(|_| "--udp-port must be a u16".to_string())?;
            }
            "--path" => cli.path = args.next().ok_or("--path requires a value")?,
            "--requests" | "-n" => {
                cli.requests = args
                    .next()
                    .ok_or("--requests requires a value")?
                    .parse()
                    .map_err(|_| "--requests must be a usize".to_string())?;
            }
            "--timeout-ms" => {
                cli.timeout_ms = args
                    .next()
                    .ok_or("--timeout-ms requires a value")?
                    .parse()
                    .map_err(|_| "--timeout-ms must be a u64".to_string())?;
            }
            "--mode" => {
                cli.mode = ShootoffMode::parse(&args.next().ok_or("--mode requires a value")?)?;
            }
            "--response-format" => {
                cli.response_format = ResponseFormat::parse(
                    &args.next().ok_or("--response-format requires a value")?,
                )?;
            }
            "--help" | "-h" => {
                return Err(
                    "usage: gnosis-foil-shootoff [--host 127.0.0.1] [--http-port 8886] [--udp-port 9086] [--requests 500] [--mode all|http|udp] [--response-format bwf2|json|any] [--path /.aeon/rf-fibonacci?n=20&repetitions=1]"
                        .to_string(),
                );
            }
            other => return Err(format!("unknown argument: {other}")),
        }
    }
    Ok(cli)
}

fn stats(samples: &[f64]) -> TimingStats {
    let mut sorted = samples.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let n = sorted.len();
    let quantile = |p: f64| -> f64 {
        let index = ((n - 1) as f64 * p).floor() as usize;
        sorted[index]
    };
    let mean = sorted.iter().sum::<f64>() / n as f64;
    let variance = if n > 1 {
        sorted
            .iter()
            .map(|value| {
                let delta = *value - mean;
                delta * delta
            })
            .sum::<f64>()
            / (n - 1) as f64
    } else {
        0.0
    };
    TimingStats {
        n,
        p50_us: quantile(0.50),
        p95_us: quantile(0.95),
        p99_us: quantile(0.99),
        mean_us: mean,
        variance_us2: variance,
        min_us: sorted[0],
        max_us: sorted[n - 1],
    }
}

fn assert_bwf2(bytes: &[u8], transport: &str) -> Result<(), String> {
    if bytes.len() != BWF2_SIZE {
        return Err(format!(
            "{transport} returned {} bytes, expected {BWF2_SIZE}",
            bytes.len()
        ));
    }
    if bytes.get(0..4) != Some(b"BWF2") {
        return Err(format!("{transport} did not return BWF2 magic"));
    }
    Ok(())
}

fn assert_bwf2_payload(bytes: &[u8], transport: &str) -> Result<(), String> {
    let response = FoilFlowFrame::decode(bytes)?;
    assert_bwf2(&response.payload, transport)
}

fn assert_json(bytes: &[u8], transport: &str) -> Result<(), String> {
    serde_json::from_slice::<serde_json::Value>(bytes)
        .map(|_| ())
        .map_err(|error| format!("{transport} did not return JSON: {error}"))
}

fn assert_json_payload(bytes: &[u8], transport: &str) -> Result<(), String> {
    let response = FoilFlowFrame::decode(bytes)?;
    assert_json(&response.payload, transport)
}

fn assert_payload(bytes: &[u8], transport: &str, format: ResponseFormat) -> Result<(), String> {
    match format {
        ResponseFormat::Bwf2 => assert_bwf2(bytes, transport),
        ResponseFormat::Json => assert_json(bytes, transport),
        ResponseFormat::Any => Ok(()),
    }
}

fn assert_flow_payload(
    bytes: &[u8],
    transport: &str,
    format: ResponseFormat,
) -> Result<(), String> {
    match format {
        ResponseFormat::Bwf2 => assert_bwf2_payload(bytes, transport),
        ResponseFormat::Json => assert_json_payload(bytes, transport),
        ResponseFormat::Any => FoilFlowFrame::decode(bytes).map(|_| ()),
    }
}

fn request_http(cli: &Cli) -> Result<Vec<u8>, String> {
    let mut stream = TcpStream::connect((cli.host.as_str(), cli.http_port))
        .map_err(|error| format!("http connect failed: {error}"))?;
    stream
        .set_read_timeout(Some(Duration::from_millis(cli.timeout_ms)))
        .map_err(|error| format!("http set_read_timeout failed: {error}"))?;
    stream
        .set_write_timeout(Some(Duration::from_millis(cli.timeout_ms)))
        .map_err(|error| format!("http set_write_timeout failed: {error}"))?;
    let request_path = if cli.response_format == ResponseFormat::Bwf2 {
        format!(
            "{}{}format=bwf2",
            cli.path,
            if cli.path.contains('?') { "&" } else { "?" }
        )
    } else {
        cli.path.clone()
    };
    let request = format!(
        "GET {} HTTP/1.1\r\nHost: {}:{}\r\nConnection: close\r\n\r\n",
        request_path, cli.host, cli.http_port
    );
    stream
        .write_all(request.as_bytes())
        .map_err(|error| format!("http write failed: {error}"))?;
    let mut response = Vec::with_capacity(512);
    stream
        .read_to_end(&mut response)
        .map_err(|error| format!("http read failed: {error}"))?;
    let body_start = response
        .windows(4)
        .position(|window| window == b"\r\n\r\n")
        .ok_or_else(|| "http response missing header terminator".to_string())?
        + 4;
    let body = response[body_start..].to_vec();
    assert_payload(&body, "http", cli.response_format)?;
    Ok(body)
}

fn make_udp_request_frame(cli: &Cli) -> Result<Vec<u8>, String> {
    FoilFlowFrame::fork_race_fold_vent(1, 0, cli.path.as_bytes().to_vec()).encode()
}

fn request_udp_reused(
    socket: &UdpSocket,
    cli: &Cli,
    frame: &mut [u8],
    sequence: u32,
) -> Result<(), String> {
    frame[2..6].copy_from_slice(&sequence.to_be_bytes());
    socket
        .send_to(frame, (cli.host.as_str(), cli.udp_port))
        .map_err(|error| format!("udp send failed: {error}"))?;
    let mut buffer = [0_u8; 2048];
    let (len, _) = socket
        .recv_from(&mut buffer)
        .map_err(|error| format!("udp recv failed: {error}"))?;
    assert_flow_payload(&buffer[..len], "udp", cli.response_format)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let cli = match parse_cli() {
        Ok(cli) => cli,
        Err(message) => {
            eprintln!("{message}");
            std::process::exit(2);
        }
    };
    let socket = UdpSocket::bind((cli.host.as_str(), 0))?;
    socket.set_read_timeout(Some(Duration::from_millis(cli.timeout_ms)))?;
    socket.set_write_timeout(Some(Duration::from_millis(cli.timeout_ms)))?;

    let mut http_times = Vec::with_capacity(cli.requests);
    let mut udp_times = Vec::with_capacity(cli.requests);
    let mut fastest_times = Vec::with_capacity(cli.requests);
    let mut http_wins = 0_usize;
    let mut udp_wins = 0_usize;

    let mut udp_request_frame = make_udp_request_frame(&cli)?;

    for index in 0..cli.requests {
        if cli.mode != ShootoffMode::Udp {
            let http_started = Instant::now();
            request_http(&cli)?;
            let http_us = http_started.elapsed().as_secs_f64() * 1_000_000.0;
            http_times.push(http_us);
            if cli.mode == ShootoffMode::Http {
                fastest_times.push(http_us);
                http_wins += 1;
                continue;
            }
        }

        if cli.mode != ShootoffMode::Http {
            let udp_started = Instant::now();
            request_udp_reused(&socket, &cli, &mut udp_request_frame, index as u32 + 1)?;
            let udp_us = udp_started.elapsed().as_secs_f64() * 1_000_000.0;
            udp_times.push(udp_us);
            if cli.mode == ShootoffMode::Udp {
                fastest_times.push(udp_us);
                udp_wins += 1;
                continue;
            }
        }

        let http_us = *http_times.last().ok_or("missing http sample")?;
        let udp_us = *udp_times.last().ok_or("missing udp sample")?;
        if http_us <= udp_us {
            http_wins += 1;
        } else {
            udp_wins += 1;
        }
        fastest_times.push(http_us.min(udp_us));
    }

    let report = ShootoffReport {
        engine: "external-gnosis-foil-control".to_string(),
        requests: cli.requests,
        http: if http_times.is_empty() {
            stats(&fastest_times)
        } else {
            stats(&http_times)
        },
        udp: if udp_times.is_empty() {
            stats(&fastest_times)
        } else {
            stats(&udp_times)
        },
        fastest: stats(&fastest_times),
        http_wins,
        udp_wins,
    };
    println!("{}", serde_json::to_string_pretty(&report)?);
    Ok(())
}
